features.snippet:
reg [31:0] a;
reg [31:0] b;
always @(*) begin
  case (sel)
    2'd0: a = b + 1;
    2'd1: a = b - 1;
    default: a = b;
  endcase
end
always @(*) begin
  b = a + 2;
end

reg [7:0] x, y;
always @(*) begin
  x = y + 1;
end
always @(*) begin
  y = x - 1;
end

reg [7:0] out;
reg [7:0] inp;
always @(*) begin
  case (state)
    2'd0: out = inp;
    2'd1: out = out + 1;
    default: out = 0;
  endcase
end
